from decimal import Decimal, InvalidOperation, ROUND_HALF_EVEN
def cast_monto(v):
    try:
        return True, Decimal(v).quantize(Decimal('0.01'), rounding=ROUND_HALF_EVEN), None
    except (InvalidOperation, TypeError):
        return False, None, f'monto invalido {v!r}'
for v in ['10.5', 'abc', '0']:
    print(v, cast_monto(v))

